"use client";

import Header from "./components/Header";

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <div className="flex h-screen flex-col">
      <Header />
      <main className="p-6 bg-gray-100 flex-1 overflow-y-auto">
        {children}
      </main>
    </div>
  );
}